CREATE TABLE `inspection_task` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `task_name` varchar(100) NOT NULL COMMENT '任务名称',
  `drone_id` bigint DEFAULT NULL COMMENT '绑定的无人机ID',
